sys_script_include.script:
var IncentNowStatementHelper = Class.create();
IncentNowStatementHelper.prototype = {

    initialize: function() {},

    // ==========================================
    // MAIN API
    // ==========================================
    getQTDAndYTD: function(user, plan, periodId) {

        var result = {
            qtd_commission: 0,
            ytd_commission: 0
        };

        if (!user || !plan || !periodId)
            return result;

        var periodGR = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
        if (!periodGR.get(periodId))
            return result;

        var periodStart = new GlideDateTime(periodGR.getValue('period_start_date'));
        var periodEnd = new GlideDateTime(periodGR.getValue('period_end_date'));

        var today = new GlideDateTime();

        // ==========================================
        // GET QUARTER START
        // ==========================================
        var quarterStart = this._getParentStart(periodStart, periodEnd, 'quarter');

        // ==========================================
        // GET YEAR START
        // ==========================================
        var yearStart = this._getParentStart(periodStart, periodEnd, 'year');

        // ==========================================
        // CALCULATE
        // ==========================================
        result.qtd_commission = this._sumMonthlyCommission(user, plan, quarterStart, today);
        result.ytd_commission = this._sumMonthlyCommission(user, plan, yearStart, today);

        return result;
    },

	getPeriodChange: function(user, plan, periodId) {

    var result = {
        change_percentage: 0,
        previous_commission: 0
    };

    var periodGR = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
    if (!periodGR.get(periodId))
        return result;

    var currentCommission = this._getPeriodCommission(user, plan, periodId);

    //  Get previous period
    var prevGR = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
    prevGR.addQuery('period_type', periodGR.getValue('period_type'));
    prevGR.addQuery('period_end_date', '<', periodGR.getValue('period_start_date'));
    prevGR.orderByDesc('period_end_date');
    prevGR.setLimit(1);
    prevGR.query();

    if (!prevGR.next())
        return result;

    var prevCommission = this._getPeriodCommission(user, plan, prevGR.getUniqueValue());

    result.previous_commission = prevCommission;

    if (prevCommission > 0) {
        var change = ((currentCommission - prevCommission) / prevCommission) * 100;
        result.change_percentage = parseFloat(change.toFixed(2));
    } else {
        result.change_percentage = 0;
    }

    return result;
},

    // ==========================================
    // GET PARENT PERIOD START (QUARTER/YEAR)
    // ==========================================
    _getParentStart: function(start, end, type) {

        var fiscalperiodGR = new GlideRecordSecure('x_ctans_incentnow_fiscal_period');
        fiscalperiodGR.addQuery('period_type', type);
        fiscalperiodGR.addQuery('period_start_date', '<=', end);
        fiscalperiodGR.addQuery('period_end_date', '>=', start);
        fiscalperiodGR.query();

        if (fiscalperiodGR.next()) {
            return new GlideDateTime(fiscalperiodGR.getValue('period_start_date'));
        }

        return null;
    },

    // ==========================================
    // SUM MONTHLY COMMISSION (CLOSED ONLY)
    // ==========================================
    _sumMonthlyCommission: function(user, plan, startDate, today) {

        if (!startDate)
            return 0;

        var total = 0;

        var metricGR = new GlideRecordSecure('x_ctans_incentnow_metric_report');
        metricGR.addQuery('user', user);
        metricGR.addQuery('plan', plan);
        metricGR.addQuery('period_type', 'month');

        // within range
        metricGR.addQuery('fiscal_period.period_start_date', '>=', startDate);

        // ONLY CLOSED MONTHS
        metricGR.addQuery('fiscal_period.period_end_date', '<', today);

        metricGR.query();

        while (metricGR.next()) {
            total += parseFloat(metricGR.getValue('total_commission')) || 0;
        }

        return parseFloat(total.toFixed(2));
    },
	_getPeriodCommission: function(user, plan, periodId) {

    var total = 0;

    var metricGR = new GlideRecordSecure('x_ctans_incentnow_metric_report');
    metricGR.addQuery('user', user);
    metricGR.addQuery('plan', plan);
    metricGR.addQuery('fiscal_period', periodId);
    metricGR.query();

    if (metricGR.next()) {
        total = parseFloat(metricGR.getValue('total_commission')) || 0;
    }

    return total;
},

    type: 'IncentNowStatementHelper'
};
